class Solution {
    public String originalDigits(String s) {
        int[] count = new int[10];
        for (char c : s.toCharArray()) {
            switch (c) {
                case 'z': count[0]++; break;
                case 'w': count[2]++; break;
                case 'u': count[4]++; break;
                case 'x': count[6]++; break;
                case 'g': count[8]++; break;
                case 'f': count[5]++; break;
                case 'h': count[6]++; break;
                case 'i': count[9]++; break;
                case 'o': count[0]++; count[1]++; count[2]++; break;
                case 'n': count[1]++; count[7]++; break;
                case 's': count[7]++; break;
                case 'r': count[3]++; break;
                case 't': count[3]++; count[7]++; break;
                case 'e': count[3]++; count[7]++; count[8]++; break;
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 10; i++) {
            sb.append(String.valueOf(i).repeat(count[i]));
        }
        return sb.toString();
    }
}
